const raw = $input.first().json;
const body = raw.body || raw;
let update = {};

if (body.callback_query) {
  const cq = body.callback_query;
  update = {
    update_type: 'callback_query',
    user_id: String(cq.from.id),
    username: cq.from.username || '',
    first_name: cq.from.first_name || 'there',
    chat_id: String(cq.message.chat.id),
    message_id: cq.message.message_id,
    callback_id: cq.id,
    callback_data: cq.data,
    text: ''
  };
} else if (body.message) {
  const msg = body.message;
  update = {
    update_type: 'message',
    user_id: String(msg.from.id),
    username: msg.from.username || '',
    first_name: msg.from.first_name || 'there',
    chat_id: String(msg.chat.id),
    message_id: msg.message_id,
    callback_id: '',
    callback_data: '',
    text: (msg.text || '').trim()
  };
} else if (body.message_id) {
  // Direct message format (Telegram Trigger may flatten the structure)
  update = {
    update_type: 'message',
    user_id: String((body.from || {}).id || ''),
    username: (body.from || {}).username || '',
    first_name: (body.from || {}).first_name || 'there',
    chat_id: String((body.chat || {}).id || ''),
    message_id: body.message_id,
    callback_id: '',
    callback_data: '',
    text: (body.text || '').trim()
  };
}

return [{ json: update }];

const products = $input.all().map(i => i.json);
const chat_id = $('🔄 Extract Telegram Data').first().json.chat_id;

if (!products.length) {
  return [{ json: { chat_id, text: '😔 No products available right now. Check back later!', keyboard: [] } }];
}

const keyboard = products.map(p => ([
  {
    text: `${p.type === 'digital' ? '💻' : '📦'} ${p.name} — ₦${Number(p.price).toLocaleString()} ${Number(p.stock) === 0 ? '(Out of Stock)' : ''}`,
    callback_data: `product_${p.id}`
  }
]));

keyboard.push([{text: '🛒 View Cart', callback_data: 'view_cart'}]);

const text = '🛍️ <b>Our Products</b>\n\nTap a product to add it to your cart:';

return [{ json: { chat_id, text, keyboard } }];

const session = $input.first().json;
const text = ($('🔄 Extract Telegram Data').first().json.text || '').trim();
const callback = $('🔄 Extract Telegram Data').first().json.callback_data || '';
const chat_id = $('🔄 Extract Telegram Data').first().json.chat_id;
const user_id = $('🔄 Extract Telegram Data').first().json.user_id;

if (text === '/cancel' || text === '/start' || callback === 'cancel_input') {
  return [{ json: { ...session, is_valid_qty: false, cancelled: true, chat_id, user_id } }];
}

const qty = parseInt(text, 10);
const isValid = !isNaN(qty) && qty > 0 && qty <= 999;

return [{
  json: {
    ...session,
    input_quantity: qty,
    is_valid_qty: isValid,
    cancelled: false,
    chat_id,
    user_id
  }
}];

const product = $input.first().json;
const session = $('🔢 Validate Quantity Input').first().json;
const qty = session.input_quantity;

let cart = [];
try {
  cart = JSON.parse(session.cart_json || '[]');
} catch(e) {
  cart = [];
}

// Check if product already in cart
const existingIdx = cart.findIndex(i => i.id === session.selected_product_id);
if (existingIdx >= 0) {
  cart[existingIdx].quantity += qty;
  cart[existingIdx].subtotal = cart[existingIdx].quantity * Number(session.selected_product_price);
} else {
  cart.push({
    id: session.selected_product_id,
    name: session.selected_product_name,
    price: Number(session.selected_product_price),
    type: session.selected_product_type,
    file_url: session.selected_product_file || '',
    quantity: qty,
    subtotal: qty * Number(session.selected_product_price)
  });
}

const total = cart.reduce((sum, i) => sum + i.subtotal, 0);

return [{
  json: {
    user_id: session.user_id,
    chat_id: session.chat_id,
    cart_json: JSON.stringify(cart),
    cart,
    total,
    product_name: session.selected_product_name,
    qty_added: qty
  }
}];

