const session = $input.first().json;
const text = ($('🔄 Extract Telegram Data').first().json.text || '').trim();
const callback = $('🔄 Extract Telegram Data').first().json.callback_data || '';
const chat_id = $('🔄 Extract Telegram Data').first().json.chat_id;
const user_id = $('🔄 Extract Telegram Data').first().json.user_id;

if (text === '/cancel' || text === '/start' || callback === 'cancel_input') {
  return [{ json: { ...session, is_valid_address: false, cancelled: true, chat_id, user_id } }];
}

const address = text;
const isValid = address.length >= 10;

return [{
  json: {
    ...session,
    input_address: address,
    is_valid_address: isValid,
    cancelled: false,
    chat_id,
    user_id
  }
}];

const session = $input.first().json;
const baseSession = $('📋 Get User Session').first().json;

let cartJson = session.cart_json || baseSession.cart_json || '[]';
let cart = [];
try { cart = JSON.parse(cartJson); } catch(e) { cart = []; }

const total = cart.reduce((s, i) => s + i.subtotal, 0);
const totalKobo = total * 100;
const orderId = `ORD-${Date.now()}-${session.user_id || baseSession.user_id}`;
const reference = `REF-${Date.now()}`;

return [{
  json: {
    order_id: orderId,
    reference,
    user_id: session.user_id || baseSession.user_id,
    chat_id: session.chat_id || baseSession.chat_id || $('🔄 Extract Telegram Data').first().json.chat_id,
    email: session.input_email || session.temp_email || baseSession.temp_email,
    address: session.input_address || session.temp_address || baseSession.temp_address || '',
    items_json: cartJson,
    cart,
    total,
    total_kobo: totalKobo,
    created_at: new Date().toISOString()
  }
}];

const headers = $input.first().json.headers;
const body = $input.first().json.body;

const signature = headers['verif-hash'];
const isValid = signature === 'flutterwave_secret_hash';

return [{
  json: {
    is_valid: isValid,
    event: body['event.type'] || body.event,
    status: body.status,
    data: body,
    reference: body.txRef || body.tx_ref,
    amount_paid: body.amount,
    customer_email: body.customer?.email || body.customer_email,
    metadata: {}
  }
}];

const order = $('📋 Find Order by Reference').first().json;
const flutterwaveData = $('🔐 Verify Flutterwave Signature').first().json;

let items = [];
try {
  items = JSON.parse(order.items_json || '[]');
} catch(e) { items = []; }

const user_id = flutterwaveData.metadata?.user_id || order.user_id;

return items.map(item => ({
  json: {
    ...item,
    order_id: order.order_id,
    user_id,
    email: order.email,
    address: order.address,
    chat_id: flutterwaveData.metadata?.chat_id || order.user_id
  }
}));

const item = $input.first().json;
let fileUrl = item.file_url || '';

// Convert Google Drive share link to direct download
if (fileUrl.includes('drive.google.com')) {
  const fileIdMatch = fileUrl.match(/\/d\/([a-zA-Z0-9_-]+)/);
  if (fileIdMatch) {
    fileUrl = `https://drive.google.com/uc?export=download&id=${fileIdMatch[1]}`;
  }
}

return [{
  json: {
    ...item,
    direct_download_url: fileUrl
  }
}];

