const allOrders = $input.all().map(i => i.json);
const chat_id = $('🔄 Extract Telegram Data').first().json.chat_id;
const userId = String($('🔄 Extract Telegram Data').first().json.user_id);

const orders = allOrders.filter(o => String(o.user_id) === userId);

if (!orders.length) {
  return [{ json: { chat_id, text: '📭 You have no orders yet.\n\nTap below to start shopping!', keyboard: [[{text: '🛍️ View Products', callback_data: 'view_products'}]] } }];
}

const sorted = orders.sort((a, b) => new Date(b.created_at) - new Date(a.created_at)).slice(0, 5);

let text = '📦 <b>Your Recent Orders</b>\n\n';
sorted.forEach((o, i) => {
  const statusIcon = o.status === 'paid' ? '✅' : o.status === 'delivered' ? '📬' : '⏳';
  const total = Number(o.total) ? '₦' + Number(o.total).toLocaleString() : '';
  text += `${i+1}. ${statusIcon} <code>${o.order_id}</code>\n   💰 ${total} — ${o.status}\n\n`;
});
text += 'Tap an order to view details:';

const keyboard = sorted.map(o => ([{text: `📋 ${o.order_id.substring(0, 25)}...`, callback_data: `order_${o.order_id}`}]));
keyboard.push([{text: '🔍 Search by Order ID', callback_data: 'search_order'}]);
keyboard.push([{text: '🛍️ Continue Shopping', callback_data: 'view_products'}]);

return [{ json: { chat_id, text, keyboard } }];

const order = $input.first().json;
const chat_id = $('🔄 Extract Telegram Data').first().json.chat_id;

if (!order || !order.order_id) {
  return [{ json: { chat_id, text: '❌ Order not found. Please check the order ID and try again.', keyboard: [[{text: '📦 My Orders', callback_data: 'my_orders'}]] } }];
}

let items = [];
try { items = JSON.parse(order.items_json || '[]'); } catch(e) { items = []; }

const statusIcon = order.status === 'paid' ? '✅' : order.status === 'delivered' ? '📬' : '⏳';
const total = Number(order.total) ? '₦' + Number(order.total).toLocaleString() : 'N/A';

let text = `📋 <b>Order Details</b>\n\n`;
text += `🆔 <code>${order.order_id}</code>\n`;
text += `${statusIcon} Status: <b>${order.status}</b>\n`;
text += `💰 Total: <b>${total}</b>\n`;
text += `📧 Email: ${order.email}\n`;
if (order.address) text += `🏠 Address: ${order.address}\n`;
text += `🕐 Created: ${new Date(order.created_at).toLocaleString('en-NG', {timeZone: 'Africa/Lagos'})}\n\n`;

text += `<b>Items:</b>\n`;
items.forEach(item => {
  const icon = item.type === 'digital' ? '💻' : '📦';
  text += `${icon} ${item.name} × ${item.quantity} — ₦${Number(item.subtotal).toLocaleString()}\n`;
});

const keyboard = [];

if (order.status === 'pending') {
  if (order.payment_link) {
    keyboard.push([{text: '💳 Pay Now', url: order.payment_link}]);
  }
} else {
  const hasDigital = items.some(i => i.type === 'digital');
  const hasPhysical = items.some(i => i.type === 'physical');
  if (hasDigital) {
    items.filter(i => i.type === 'digital' && i.file_url).forEach(item => {
      let downloadUrl = item.file_url;
      const driveMatch = downloadUrl.match(/\/d\/([a-zA-Z0-9_-]+)/);
      if (driveMatch) downloadUrl = `https://drive.google.com/uc?export=download&id=${driveMatch[1]}`;
      keyboard.push([{text: `📥 Download ${item.name}`, url: downloadUrl}]);
    });
  }
  if (hasPhysical) {
    keyboard.push([{text: '🚚 Track Order', callback_data: `track_${order.order_id}`}]);
  }
}
keyboard.push([{text: '📦 My Orders', callback_data: 'my_orders'}, {text: '🛍️ Shop', callback_data: 'view_products'}]);

return [{ json: { chat_id, text, keyboard } }];

